);    }    public void Update(Auth auth)    {        ArgumentNullException.ThrowIfNull(auth);        db.Auths.Update(auth);    }    public void Remove(Auth auth)    {        ArgumentNullException.ThrowIfNull(auth);        db.Auths.Remove(auth);    }    #endregion}